import React, { useState } from 'react';
import './login-page.css'; // Custom CSS for styling the login page
import Header from '../../components/Header/Header';
import Footer from '../../components/Footer/Footer';
import { sendLoginToBackend } from '../../api.js'; // Importing the backend API function

const LoginPage: React.FC = () => {
  const [email, setEmail] = useState<string>(''); // State for email input
  const [password, setPassword] = useState<string>(''); // State for password input
  const [userType, setUserType] = useState<string>('admin'); // State for user type selection
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false); // State to manage form submission

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault(); // Prevent default form submission
    if (isSubmitting) return; // Prevent multiple submissions

    // Basic validation
    if (!email.trim() || !password.trim()) {
      alert('Please fill in all fields.');
      return;
    }

    setIsSubmitting(true); // Set submitting state
    try {
      // Send login details to backend
      const response = await sendLoginToBackend(email, password);
      console.log('Login successful:', response);
      alert(`Welcome, ${userType}!`);

      // Redirect logic based on userType (e.g., use React Router's useNavigate hook)
      // Example:
      // if (userType === 'admin') navigate('/admin-dashboard');
      // else if (userType === 'staff') navigate('/staff-dashboard');
      // else navigate('/student-dashboard');
    } catch (error) {
      console.error('Login failed:', error);
      alert('Invalid credentials. Please try again.');
    } finally {
      setIsSubmitting(false); // Reset submitting state
    }
  };

  return (
    <div className="login-page">
      <Header />
      <div className="login-container">
        <h2>Login</h2>
        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="userType">User Type</label>
            <select
              id="userType"
              value={userType}
              onChange={(e) => setUserType(e.target.value)}
            >
              <option value="admin">Admin</option>
              <option value="staff">Staff</option>
              <option value="student">Student</option>
            </select>
          </div>
          <button type="submit" disabled={isSubmitting} className="login-button">
            {isSubmitting ? 'Logging in...' : 'Login'}
          </button>
        </form>
      </div>
      <Footer />
    </div>
  );
};

export default LoginPage;
